import React, { useState, useEffect } from 'react';
import { InputText } from 'primereact/inputtext';
import { InputNumber } from 'primereact/inputnumber';
import { Dropdown } from 'primereact/dropdown';
import { Button } from 'primereact/button';
import { Divider } from 'primereact/divider';
import { classNames } from 'primereact/utils';
import { useParams, useNavigate } from "react-router-dom";

import LoginService from "../../services/loginService";
import {ProgressSpinner} from "primereact/progressspinner";

export default function PassBackUp() {
    const params = useParams();
    const navigate = useNavigate();
    const esNuevo = !('idArticulo' in params);

    const recuperarPassItemVacio = { username: "", email: ""};
    const [username, setUsername] = useState("");
    const [email, setEmail] = useState("");
    const [recuperarPassItem, setRecuperarPassItem] = useState(recuperarPassItemVacio);
    const [cargando, setCargando] = useState(true);

    useEffect(() => {
        // if (!esNuevo) {
        //     loginService.buscarPorId(params.idArticulo).then(res => setUsuario(res.data));
        // }
        // familiaService.buscarTodas().then(res => setFamilias(res.data));
    },[]);

    function recuperarPass(){
        setCargando(true);
        setRecuperarPassItem(username, email);
        LoginService.recuperarPass(recuperarPassItem).then(res => {
            setCargando(false);
        });
    }

    function onUsernameChange(e){
        setUsername(e.target.value);
    }

    function onEmailChange(e){
        setEmail(e.target.value);
    }

    function login() {
        navigate("login"); // navega a URL para creacion de nuevo cliente
    }

    return (
        <div>
            {/* Contenido de la página */}
            <div className="text-3xl text-800 font-bold mb-4"> Iniciar Sesión </div>

            <div className="grid">
                <InputText id="username" className="col-6 mr-2" onChange={onUsernameChange} />
                <InputText id="email" className="col-6 mr-2" onChange={onEmailChange} />
                <Button label="recuperarPass" className="col-1 mr-2" onClick={recuperarPass} />
            </div>

            <div className="flex justify-content-end">
                <Button label="login" icon="pi pi-plus" className="p-button-lg" onClick={login} tooltip="Volver al login" tooltipOptions={{ position: 'bottom' }} />
            </div>

            {cargando && <div> <ProgressSpinner /> Cargando... </div>}

            <div className="recuadro" style= {{border:'1px solid black',padding:'10px',margin:'10px',backgroundColor:'lightgray'}}>
                <p>El correo de recuperación se ha enviado correctamente.</p>
                <button onClick={login}>Aceptar</button>
            </div>

        </div>
    );
}
